class Vozilo { 
  private String znamka; 
  public Vozilo() { 
    znamka = "Proizvajalec"; 
  } 
  public void zatrobi() { 
    System.out.println("Cin cin!"); 
  } 
} 
class Avto extends Vozilo { 
  private String model; 
  public Avto() { 
    model = "Prvi model"; 
  } 
  public static void main(String[] args) { 
    Avto mojAvto = new Avto(); 
    mojAvto.zatrobi(); 
    System.out.println(mojAvto.znamka); 
    System.out.println(mojAvto.model); 
  } 
} 
