20.1. Napišite razred Tocka3D, ki ustreza spodnjemu razredu Tocka2D, programu in izpisu. 
RAZRED Tocka2D 
class Tocka2D { 
    protected double x; 
    protected double y; 
    public Tocka2D(double x, double y) { 
       this.x = x; 
       this.y = y; 
    } 
    public double vrniMin() { 
        return Math.min(x, y); 
    } 
} 
PROGRAM 
public class Test{ 
     public static void main(String []args){ 
        Tocka2D t1 = new Tocka2D(-3.4, 2.5); 
        Tocka2D t2 = new Tocka3D(2.1, 1.3, -2); 
        System.out.println(t1.vrniMin()); 
        System.out.println(t2.vrniMin()); 
     } 
} 
IZPIS 
-3.4 
-2.0
